INSERT IGNORE INTO practice_set_question(practice_set_id, question_id, sort_no, score) SELECT ps.id, qb.id, CASE qb.type WHEN 'SINGLE' THEN 1 WHEN 'MULTIPLE' THEN 2 WHEN 'JUDGE' THEN 3 WHEN 'FILL' THEN 4 WHEN 'SHORT' THEN 5 END, CASE qb.type WHEN 'SINGLE' THEN 1.00 WHEN 'MULTIPLE' THEN 2.00 WHEN 'JUDGE' THEN 1.00 WHEN 'FILL' THEN 2.00 WHEN 'SHORT' THEN 4.00 END FROM practice_set ps JOIN question_bank qb ON qb.course_id = ps.course_id AND qb.chapter_id = ps.chapter_id WHERE ps.course_id = 33 AND ps.chapter_id = 137 AND ps.title = '第五章 写作模板与翻译训练 - Chapter Practice' AND qb.stem IN ('For course [英语听说读写综合提升], which statement best matches the core idea of chapter [写作模板与翻译训练]?', 'For chapter [写作模板与翻译训练], which of the following are reasonable learning goals?', 'True or False: Combining concept understanding with practice is an effective way to learn chapter [写作模板与翻译训练].', 'Fill in the blank: Besides understanding theory, chapter [写作模板与翻译训练] also emphasizes practical ______.', 'Short answer: Briefly explain the major learning focus and practical suggestions for chapter [写作模板与翻译训练] in course [英语听说读写综合提升].');
